head.b:skin:
  :root {
    /* CYBERPUNK COLOR PALETTE */
    --bg-base: #05050a;
    --neon-cyan: #00f3ff;
    --neon-cyan-dim: rgba(0, 243, 255, 0.2);
    --neon-pink: #ff007f;
    --neon-pink-dim: rgba(255, 0, 127, 0.2);
    --neon-yellow: #fdee00;
    --text-main: #e0e6ed;
    --text-muted: #8b9bb4;
    
    /* CARD & READABILITY VARIABLES */
    --card-bg: rgba(8, 10, 15, 0.85); /* Dark solid tint */
    --card-border: rgba(0, 243, 255, 0.3);
    
    --font-head: 'Orbitron', sans-serif;
    --font-body: 'Rajdhani', sans-serif;
  }
  
  /* OVERDRIVE MODE (Swaps Cyan to Pink as primary) */
  [data-theme="overdrive"] {
    --neon-cyan: #ff007f;
    --neon-cyan-dim: rgba(255, 0, 127, 0.2);
    --neon-pink: #00f3ff;
    --neon-pink-dim: rgba(0, 243, 255, 0.2);
    --card-border: rgba(255, 0, 127, 0.3);
  }
  
  * { margin:0; padding:0; box-sizing:border-box; }
  ::selection { background: var(--neon-cyan); color: #000; }
  html { scroll-behavior: smooth; }
  body {
    font-family: var(--font-body);
    font-size: 1.15rem;
    background: var(--bg-base);
    color: var(--text-main);
    transition: color 0.3s;
    overflow-x: hidden;
  }
  
  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-head);
    text-transform: uppercase;
    letter-spacing: 1px;
    color: #fff;
  }
  a { text-decoration: none; }

  /* ── AMBIENT CYBER BACKGROUND (Readability Safe) ── */
  .cyber-bg {
    position: fixed; inset: 0; z-index: -5; background: var(--bg-base); overflow: hidden; pointer-events: none;
  }
  /* Perspective Grid */
  .cyber-grid {
    position: absolute; bottom: -20vh; left: -50vw; width: 200vw; height: 100vh;
    background-image: 
      linear-gradient(var(--neon-cyan-dim) 1px, transparent 1px),
      linear-gradient(90deg, var(--neon-cyan-dim) 1px, transparent 1px);
    background-size: 60px 60px;
    transform: perspective(600px) rotateX(75deg);
    animation: gridScroll 15s linear infinite;
    mask-image: linear-gradient(to top, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 80%);
    -webkit-mask-image: linear-gradient(to top, rgba(0,0,0,1) 0%, rgba(0,0,0,0) 80%);
    transition: background-image 0.5s;
  }
  @keyframes gridScroll {
    0% { transform: perspective(600px) rotateX(75deg) translateY(0); }
    100% { transform: perspective(600px) rotateX(75deg) translateY(60px); }
  }
  
  /* Floating Glowing Orbs */
  .glow-orb { position: absolute; border-radius: 50%; filter: blur(80px); opacity: 0.15; animation: floatOrb 20s ease-in-out infinite alternate; transition: background 0.5s; }
  .orb-1 { width: 40vw; height: 40vw; background: var(--neon-cyan); top: -10%; left: -10%; }
  .orb-2 { width: 30vw; height: 30vw; background: var(--neon-pink); bottom: 10%; right: -5%; animation-delay: -5s; animation-direction: alternate-reverse; }
  @keyframes floatOrb {
    0% { transform: translate(0, 0) scale(1); }
    100% { transform: translate(30px, 50px) scale(1.1); }
  }

  /* ── PROGRESS BAR ── */
  #reading-progress {
    position: fixed; top: 0; left: 0; height: 3px;
    background: linear-gradient(90deg, var(--neon-cyan), var(--neon-pink));
    z-index: 99999; width: 0%; transition: width 0.1s linear;
    box-shadow: 0 0 10px var(--neon-cyan);
  }

  /* ── SCROLL REVEAL ── */
  .reveal { opacity: 0; transform: translateY(30px); transition: opacity 0.6s ease-out, transform 0.6s ease-out; }
  .reveal.visible { opacity: 1; transform: translateY(0); }
  .delay-1 { transition-delay: 0.1s; }
  .delay-2 { transition-delay: 0.2s; }

  /* ── GLITCH HOVER ── */
  .glitch-hover:hover {
    animation: textGlitch 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94) both infinite;
    color: var(--neon-cyan); text-shadow: -2px 0 var(--neon-pink), 2px 0 var(--neon-yellow);
  }
  @keyframes textGlitch {
    0% { transform: translate(0) } 20% { transform: translate(-2px, 1px) }
    40% { transform: translate(-1px, -1px) } 60% { transform: translate(2px, 1px) }
    80% { transform: translate(1px, -1px) } 100% { transform: translate(0) }
  }
  
  /* ── NAV ── */
  nav { position: sticky; top: 0; z-index: 100; background: rgba(5,5,10,0.8); backdrop-filter: blur(10px); border-bottom: 1px solid var(--neon-cyan-dim); }
  .nav-container { display: flex; align-items: center; justify-content: space-between; width: 100%; max-width: 1200px; padding: 1rem 2rem; margin: 0 auto; }
  .nav-logo-section .widget { margin: 0; }
  .nav-logo { font-size: 1.8rem; font-weight: 900; color: #fff; text-shadow: 0 0 10px var(--neon-cyan-dim); }
  .nav-logo span { color: var(--neon-cyan); }
  
  .nav-right { display: flex; align-items: center; gap: 2rem; }
  .nav-links-wrapper .widget { margin: 0; }
  .nav-links { display: flex; gap: 2rem; list-style: none; align-items: center; margin: 0; padding: 0; }
  .nav-links a { font-family: var(--font-head); color: var(--text-main); font-size: 0.9rem; font-weight: 700; text-transform: uppercase; transition: all 0.3s; letter-spacing: 1px; }
  .nav-links a:hover { color: var(--neon-cyan); text-shadow: 0 0 8px var(--neon-cyan); }
  
  /* ── DROPDOWN ── */
  .dropdown { position: relative; display: inline-block; }
  .dropdown .dropbtn { cursor: pointer; display: flex; align-items: center; gap: 4px; }
  .dropdown-content { display: none; position: absolute; background-color: var(--card-bg); backdrop-filter: blur(10px); border: 1px solid var(--neon-cyan); border-top: 3px solid var(--neon-cyan); min-width: 200px; top: 100%; left: -1rem; z-index: 101; padding: 0; box-shadow: 0 10px 30px rgba(0,0,0,0.8); }
  .dropdown-content a { color: var(--text-main); padding: 1rem 1.5rem; display: block; font-family: var(--font-body); font-size: 1.1rem; border-bottom: 1px solid rgba(255,255,255,0.05); transition: all 0.2s; }
  .dropdown-content a:hover { background-color: var(--neon-cyan-dim); color: var(--neon-cyan); padding-left: 2rem; }
  .dropdown:hover .dropdown-content { display: block; }
  
  .hamburger { display: none; background: none; border: none; cursor: pointer; padding: 0.5rem; }
  .hamburger svg { width: 32px; height: 32px; fill: var(--neon-cyan); filter: drop-shadow(0 0 5px var(--neon-cyan)); }

  /* ── SEARCH BAR ── */
  .search-form { display: flex; align-items: center; position: relative; }
  .search-input { background: rgba(0,0,0,0.5); border: 1px solid var(--neon-cyan-dim); color: var(--text-main); padding: 0.5rem 1rem 0.5rem 2.2rem; font-family: var(--font-body); font-size: 1rem; width: 160px; transition: all 0.3s; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); }
  .search-input::placeholder { color: var(--text-muted); }
  .search-input:focus { outline: none; border-color: var(--neon-cyan); width: 200px; box-shadow: inset 0 0 10px var(--neon-cyan-dim); }
  .search-btn { position: absolute; left: 10px; background: none; border: none; padding: 0; display: flex; align-items: center; justify-content: center; cursor: pointer; }
  .search-btn svg { width: 16px; height: 16px; fill: var(--text-muted); transition: fill 0.2s; }
  .search-input:focus + .search-btn svg, .search-btn:hover svg { fill: var(--neon-cyan); }

  /* ── OVERDRIVE TOGGLE ── */
  #theme-toggle { background: transparent; border: 1px solid var(--neon-cyan); color: var(--neon-cyan); font-family: var(--font-head); font-size: 0.75rem; padding: 0.4rem 0.8rem; cursor: pointer; text-transform: uppercase; transition: all 0.3s; letter-spacing: 1px; clip-path: polygon(5px 0, 100% 0, 100% calc(100% - 5px), calc(100% - 5px) 100%, 0 100%, 0 5px); }
  #theme-toggle:hover { background: var(--neon-cyan); color: #000; box-shadow: 0 0 15px var(--neon-cyan); }

  /* ── CYBER BUTTONS ── */
  .btn-primary, .btn-secondary {
    display: inline-flex; align-items: center; gap: 8px; padding: 1rem 2rem;
    font-family: var(--font-head); font-weight: 700; font-size: 0.95rem; text-transform: uppercase; letter-spacing: 1.5px;
    text-decoration: none; border: none; cursor: pointer; position: relative;
    transition: all 0.3s;
    clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px);
  }
  .btn-primary {
    background: var(--neon-cyan); color: #000 !important;
    box-shadow: 0 0 15px var(--neon-cyan-dim);
  }
  .btn-primary:hover {
    background: #fff; color: #000 !important;
    box-shadow: 0 0 25px var(--neon-cyan); transform: scale(1.02);
  }
  .btn-secondary {
    background: rgba(255, 0, 127, 0.1); color: var(--neon-pink) !important;
    border: 1px solid var(--neon-pink);
  }
  .btn-secondary:hover {
    background: var(--neon-pink); color: #000 !important;
    box-shadow: 0 0 25px var(--neon-pink); transform: scale(1.02);
  }

  /* ── CYBER CARDS (Ensures Readability) ── */
  .cyber-card {
    background: var(--card-bg);
    backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
    border: 1px solid var(--card-border);
    clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px);
    padding: 2.5rem; transition: all 0.3s; position: relative; z-index: 10;
  }
  .cyber-card::before { content: ''; position: absolute; top: 0; left: 0; width: 30px; height: 3px; background: var(--neon-cyan); transition: width 0.3s; }
  .cyber-card:hover { border-color: var(--neon-cyan); box-shadow: 0 10px 30px rgba(0,0,0,0.5), inset 0 0 15px var(--neon-cyan-dim); transform: translateY(-5px); }
  .cyber-card:hover::before { width: 100%; }

  /* ── HERO ── */
  .hero { min-height: 80vh; padding: 4rem 2rem; position: relative; display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 10; text-align: center; }
  .hero-tag { display: inline-flex; align-items: center; gap: 10px; background: var(--neon-cyan-dim); border: 1px solid var(--neon-cyan); padding: 6px 16px; font-family: var(--font-head); font-size: 0.8rem; font-weight: 700; color: var(--neon-cyan); letter-spacing: 2px; text-transform: uppercase; margin-bottom: 2rem; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); }
  .hero-tag .dot { width: 8px; height: 8px; background: var(--neon-cyan); animation: blink 1s infinite; }
  @keyframes blink { 50% { opacity: 0; } }
  .hero-title { font-size: clamp(3rem, 6vw, 5.5rem); font-weight: 900; line-height: 1.1; margin-bottom: 1.5rem; text-shadow: 2px 2px 0 var(--neon-pink); }
  .hero-title span { color: transparent; -webkit-text-stroke: 2px var(--neon-cyan); text-shadow: 0 0 15px var(--neon-cyan-dim); }
  .hero-desc { font-size: 1.25rem; font-weight: 500; line-height: 1.6; color: var(--text-muted); margin: 0 auto 3rem auto; max-width: 700px; background: rgba(0,0,0,0.4); padding: 10px 20px; border-radius: 8px; backdrop-filter: blur(5px); }
  .hero-actions { display: flex; gap: 1.5rem; flex-wrap: wrap; justify-content: center; }

  /* ── GITHUB & YOUTUBE GRID ── */
  .stats-yt-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; width: 100%; max-width: 1100px; margin-top: 4rem; z-index: 10; }
  .social-banner { @extend .cyber-card; text-align: center; display: flex; flex-direction: column; align-items: center; gap: 1.5rem; padding: 3.5rem 2rem; }
  .social-banner .icon { width: 64px; height: 64px; fill: var(--text-main); margin-bottom: -0.5rem; transition: all 0.3s; }
  .social-banner h2 { font-size: 1.6rem; margin-bottom: 0.5rem; }
  .social-banner p { color: var(--text-muted); line-height: 1.6; max-width: 400px; margin: 0 auto; }
  .social-banner.git:hover { border-color: #fff; }
  .social-banner.git:hover .icon { fill: var(--neon-cyan); filter: drop-shadow(0 0 10px var(--neon-cyan)); }
  .social-banner.yt::before { background: #ff0000; }
  .social-banner.yt:hover { border-color: #ff0000; box-shadow: 0 10px 30px rgba(0,0,0,0.5), inset 0 0 15px rgba(255,0,0,0.2); }
  .social-banner.yt:hover .icon { fill: #ff0000; filter: drop-shadow(0 0 10px #ff0000); }

  /* ── SECTIONS ── */
  section.standard-section { padding: 5rem 2rem; max-width: 1200px; margin: 0 auto; width: 100%; position: relative; z-index: 10; }
  .section-label { display: inline-flex; align-items: center; gap: 10px; font-family: var(--font-head); font-size: 0.9rem; color: var(--neon-pink); font-weight: 700; letter-spacing: 2px; text-transform: uppercase; margin-bottom: 1rem; }
  .section-label::before { content: ''; width: 30px; height: 2px; background: var(--neon-pink); }
  .section-title { font-size: clamp(2.2rem, 4vw, 3.5rem); font-weight: 900; letter-spacing: 1px; margin-bottom: 3rem; text-shadow: 0 0 10px rgba(0,0,0,0.5); }

  /* ── ABOUT ── */
  .about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; }
  .about-text { color: var(--text-main); line-height: 1.8; font-size: 1.15rem; }
  .about-text p + p { margin-top: 1.5rem; }
  .about-highlights { display: flex; flex-direction: column; gap: 1.5rem; }
  .highlight-item { background: rgba(0,0,0,0.4); border-left: 3px solid var(--neon-cyan); padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1.25rem; transition: all 0.3s; }
  .highlight-item:hover { background: rgba(0,243,255,0.05); transform: translateX(10px); }
  .highlight-icon { font-size: 2rem; flex-shrink: 0; filter: drop-shadow(0 0 5px var(--neon-cyan)); }
  .highlight-info strong { font-family: var(--font-head); font-size: 1.1rem; color: var(--neon-cyan); display: block; margin-bottom: 4px; letter-spacing: 1px; }
  .highlight-info span { font-size: 1rem; color: var(--text-muted); }
  
  /* ── EXPERIENCE TIMELINE ── */
  .timeline { display: flex; flex-direction: column; position: relative; margin-left: 20px; }
  .timeline::before { content: ''; position: absolute; left: 0; top: 0; bottom: 0; width: 2px; background: var(--neon-cyan-dim); }
  .timeline-item { display: flex; gap: 2rem; padding: 0 0 3rem 0; position: relative; }
  .timeline-dot { width: 20px; height: 20px; background: var(--bg-base); border: 2px solid var(--neon-cyan); border-radius: 50%; position: absolute; left: -9px; top: 0; z-index: 1; transition: all 0.3s; box-shadow: 0 0 10px var(--neon-cyan); }
  .timeline-item:hover .timeline-dot { background: var(--neon-cyan); transform: scale(1.3); }
  .timeline-body { @extend .cyber-card; flex: 1; padding: 2rem; margin-top: -10px; }
  .timeline-period { font-family: var(--font-head); font-size: 0.9rem; color: var(--neon-pink); margin-bottom: 8px; letter-spacing: 1px; font-weight: 700; }
  .timeline-role { font-family: var(--font-head); font-size: 1.4rem; font-weight: 700; margin-bottom: 4px; color: #fff; }
  .timeline-org { font-size: 1.1rem; color: var(--text-muted); margin-bottom: 1.5rem; }
  .timeline-points { list-style: none; display: flex; flex-direction: column; gap: 10px; }
  .timeline-points li { font-size: 1.1rem; color: var(--text-main); line-height: 1.6; padding-left: 1.5rem; position: relative; }
  .timeline-points li::before { content: '>'; font-family: var(--font-head); font-weight: 900; position: absolute; left: 0; color: var(--neon-cyan); top: 2px; }

  /* ── PROJECTS ── */
  .projects-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; }
  .project-card { @extend .cyber-card; }
  .project-date { font-family: var(--font-head); font-size: 0.85rem; font-weight: 700; color: var(--neon-yellow); margin-bottom: 1rem; letter-spacing: 1px; }
  .project-name { font-family: var(--font-head); font-size: 1.3rem; font-weight: 700; margin-bottom: 1rem; color: #fff; }
  .project-desc { font-size: 1.1rem; color: var(--text-muted); line-height: 1.6; }

  /* ── BLOG GRID ── */
  .blog-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; }
  .blog-card { @extend .cyber-card; display: flex; flex-direction: column; }
  .blog-date { font-family: var(--font-head); font-size: 0.85rem; font-weight: 700; color: var(--neon-cyan); margin-bottom: 1rem; letter-spacing: 1px; }
  .blog-title { font-family: var(--font-head); font-size: 1.4rem; font-weight: 700; margin-bottom: 1rem; line-height: 1.3; }
  .blog-title a { color: #fff; transition: color 0.3s; }
  .blog-title a:hover { color: var(--neon-cyan); }
  .blog-snippet { font-size: 1.1rem; color: var(--text-muted); line-height: 1.6; margin-bottom: 1.5rem; flex-grow: 1; }
  .read-more { display: inline-flex; align-items: center; font-family: var(--font-head); font-size: 0.95rem; font-weight: 700; color: var(--neon-pink); text-transform: uppercase; align-self: flex-start; transition: all 0.3s; padding-bottom: 2px; border-bottom: 2px solid transparent; }
  .read-more:hover { border-color: var(--neon-pink); text-shadow: 0 0 8px var(--neon-pink); letter-spacing: 1px; }
  
  /* ── FULL POST VIEW ── */
  .post-container { @extend .cyber-card; max-width: 900px; margin: 2rem auto; padding: 3rem; }
  @media (max-width: 768px) { .post-container { padding: 2rem 1.5rem; } }
  
  .post-header { text-align: center; margin-bottom: 3rem; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 2rem; }
  .post-header h1 { font-size: clamp(2rem, 5vw, 3.5rem); margin: 1rem 0; line-height: 1.2; font-weight: 900; }
  .post-meta-tags { display: flex; flex-wrap: wrap; justify-content: center; gap: 1rem; font-family: var(--font-head); font-size: 0.9rem; font-weight: 700; margin-top: 1.5rem; letter-spacing: 1px; color: var(--text-muted); }
  .post-tag { color: var(--neon-cyan); }
  
  .post-hero-image { width: 100%; aspect-ratio: 16 / 9; overflow: hidden; clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px); border: 1px solid var(--neon-cyan-dim); margin: 0 auto 3rem auto; }
  .post-hero-image img { width: 100% !important; height: 100% !important; object-fit: cover !important; }

  .post-body .separator, .post-body img { display: none !important; }
  .post-body { font-size: 1.2rem; line-height: 1.8; color: var(--text-main); }
  .post-body h2, .post-body h3 { font-family: var(--font-head); color: var(--neon-cyan); margin: 3rem 0 1.5rem; font-weight: 700; }
  .post-body p { margin-bottom: 1.5rem; }
  .post-body a { color: var(--neon-pink); border-bottom: 1px dashed var(--neon-pink); transition: all 0.2s; }
  .post-body a:hover { color: #fff; border-bottom-style: solid; background: var(--neon-pink-dim); }
  
  .post-body blockquote { border-left: 4px solid var(--neon-pink); background: rgba(255,0,127,0.05); padding: 1.5rem 2rem; margin: 2.5rem 0; font-style: italic; clip-path: polygon(0 0, 100% 0, 100% 100%, 20px 100%, 0 calc(100% - 20px)); }
  .post-body pre { background: #000; border: 1px solid var(--card-border); padding: 1.5rem; overflow-x: auto; margin: 2.5rem 0; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); }
  .post-body code { font-family: 'Courier New', monospace; font-size: 1rem; color: var(--neon-yellow); }

  /* ── SKILLS ── */
  .skills-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1.5rem; }
  .skill-category { @extend .cyber-card; padding: 2rem; }
  .skill-cat-title { font-family: var(--font-head); font-size: 1rem; font-weight: 700; text-transform: uppercase; letter-spacing: 2px; color: var(--neon-cyan); margin-bottom: 1.5rem; }
  .skill-tags { display: flex; flex-wrap: wrap; gap: 10px; }
  .skill-tag { padding: 6px 14px; background: rgba(0,0,0,0.5); border: 1px solid var(--card-border); font-family: var(--font-head); font-size: 0.85rem; font-weight: 700; color: var(--text-main); letter-spacing: 1px; transition: all 0.3s; clip-path: polygon(8px 0, 100% 0, 100% calc(100% - 8px), calc(100% - 8px) 100%, 0 100%, 0 8px); }
  .skill-tag:hover { background: var(--neon-cyan-dim); color: var(--neon-cyan); border-color: var(--neon-cyan); }

  .certs-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 1.5rem; margin-top: 2rem; }
  .cert-card { @extend .cyber-card; padding: 1.5rem; border-top: 2px solid var(--neon-pink); }
  .cert-issuer { font-family: var(--font-head); font-size: 0.85rem; font-weight: 700; color: var(--neon-pink); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 8px; }
  .cert-name { font-size: 1.15rem; font-weight: 600; margin-bottom: 6px; color: #fff; }

  /* ── CONTACT ── */
  .contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; }
  .contact-info { display: flex; flex-direction: column; gap: 1.5rem; }
  .contact-item { background: rgba(0,0,0,0.4); border: 1px solid var(--neon-cyan-dim); padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1.5rem; color: var(--text-main); transition: all 0.3s; clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px); }
  .contact-item:hover { border-color: var(--neon-cyan); background: var(--neon-cyan-dim); transform: translateX(10px); }
  .contact-icon { font-size: 1.5rem; flex-shrink: 0; filter: drop-shadow(0 0 5px var(--neon-cyan)); }
  .contact-label { font-family: var(--font-head); font-size: 0.85rem; font-weight: 700; color: var(--neon-cyan); margin-bottom: 4px; letter-spacing: 1px; text-transform: uppercase; }
  .contact-value { font-size: 1.1rem; font-weight: 600; }
  
  .contact-card { @extend .cyber-card; display: flex; flex-direction: column; justify-content: center; gap: 1.5rem; border-color: var(--neon-pink); }
  .contact-card::before { background: var(--neon-pink); }
  .contact-card:hover { border-color: var(--neon-pink); box-shadow: 0 10px 30px rgba(0,0,0,0.5), inset 0 0 15px var(--neon-pink-dim); }
  .contact-card h3 { font-family: var(--font-head); font-size: 1.8rem; font-weight: 900; }
  .contact-card p { font-size: 1.15rem; color: var(--text-muted); line-height: 1.6; }

  /* ── ADS / SPONSOR BLOCKS ── */
  .ad-sponsor-block {
    margin: 2rem auto; text-align: center; min-height: 100px; 
    background: rgba(0,0,0,0.8); border: 1px solid var(--card-border);
    clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px);
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    position: relative; padding: 1rem; z-index: 10;
  }
  .ad-sponsor-label {
    position: absolute; top: 0; left: 20px; background: var(--neon-cyan); color: #000;
    font-family: var(--font-head); font-size: 0.7rem; font-weight: 900; padding: 2px 10px;
    letter-spacing: 2px; text-transform: uppercase; clip-path: polygon(0 0, 100% 0, 90% 100%, 0% 100%);
  }

  /* ── FOOTER & SOCIAL ICONS ── */
  .site-footer { border-top: 1px solid var(--neon-cyan); background: rgba(5,5,10,0.95); padding: 3rem 2rem; margin-top: 5rem; position: relative; z-index: 10; text-align: center; }
  .footer-bottom { max-width: 1200px; margin: 0 auto; display: flex; flex-direction: column; gap: 2rem; align-items: center; }
  
  .social-links { display: flex; gap: 1.5rem; justify-content: center; flex-wrap: wrap; }
  .social-icon { display: flex; align-items: center; justify-content: center; width: 45px; height: 45px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: 50%; color: var(--text-main); transition: all 0.3s ease; }
  .social-icon svg { width: 20px; height: 20px; fill: currentColor; }
  .social-icon:hover { transform: translateY(-5px); background: var(--card-bg); border-color: var(--neon-cyan); color: var(--neon-cyan); box-shadow: 0 0 15px var(--neon-cyan-dim); }
  .social-icon.insta:hover { color: #E1306C; border-color: #E1306C; box-shadow: 0 0 15px rgba(225, 48, 108, 0.4); }
  .social-icon.yt:hover { color: #FF0000; border-color: #FF0000; box-shadow: 0 0 15px rgba(255, 0, 0, 0.4); }
  .social-icon.tg:hover { color: #0088cc; border-color: #0088cc; box-shadow: 0 0 15px rgba(0, 136, 204, 0.4); }
  .social-icon.in:hover { color: #0077b5; border-color: #0077b5; box-shadow: 0 0 15px rgba(0, 119, 181, 0.4); }
  .social-icon.be:hover { color: #1769ff; border-color: #1769ff; box-shadow: 0 0 15px rgba(23, 105, 255, 0.4); }

  .footer-text { font-size: 1rem; color: var(--text-muted); display: flex; flex-wrap: wrap; justify-content: center; gap: 2rem; width: 100%; border-top: 1px solid rgba(255,255,255,0.05); padding-top: 2rem; }
  .inline-legal-links { display: flex; gap: 1.5rem; }
  .inline-legal-links a { font-family: var(--font-head); color: var(--text-muted); font-size: 0.85rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; transition: color 0.3s; }
  .inline-legal-links a:hover { color: var(--neon-pink); }
  .footer-credit span { color: var(--neon-cyan); font-family: var(--font-head); font-weight: 700; letter-spacing: 1px; }

  /* ── MOBILE VIEW ── */
  @media (max-width: 768px) {
    .hero { padding: 6rem 2rem 3rem; }
    .stats-yt-grid, .about-grid, .contact-grid { grid-template-columns: 1fr; }
    .hamburger { display: block; }
    .nav-right {
      display: none; position: absolute; top: 100%; left: 0; width: 100%;
      background: rgba(5,5,10,0.95); backdrop-filter: blur(10px); border-bottom: 1px solid var(--neon-cyan);
      flex-direction: column; padding: 2rem; gap: 1.5rem; z-index: 100;
    }
    .nav-right.active { display: flex; }
    .nav-links { flex-direction: column; width: 100%; gap: 1.5rem; }
    .search-form { width: 100%; order: -1; margin-bottom: 1rem; }
    .search-input { width: 100%; }
    .dropdown-content { position: static; box-shadow: none; border: none; border-left: 2px solid var(--neon-cyan); padding-left: 1rem; margin-top: 1rem; background: transparent; display: none; }
    .dropdown:hover .dropdown-content { display: block; }
    .footer-text { flex-direction: column; gap: 1rem; text-align: center; }
  }
  
  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: var(--bg-base); }
  ::-webkit-scrollbar-thumb { background: var(--neon-cyan-dim); border: 1px solid var(--neon-cyan); }
  ::-webkit-scrollbar-thumb:hover { background: var(--neon-cyan); }
  [data-theme="overdrive"] ::-webkit-scrollbar-thumb { border-color: var(--neon-pink); background: var(--neon-pink-dim); }
  [data-theme="overdrive"] ::-webkit-scrollbar-thumb:hover { background: var(--neon-pink); }

body.script:
//
  /* ── OVERDRIVE (THEME) TOGGLE ── */
  function toggleTheme() {
    const body = document.body;
    const current = body.getAttribute('data-theme');
    body.setAttribute('data-theme', current === 'overdrive' ? '' : 'overdrive');
    localStorage.setItem('theme', body.getAttribute('data-theme'));
  }
  
  (function() {
    const saved = localStorage.getItem('theme');
    if (saved === 'overdrive') document.body.setAttribute('data-theme', 'overdrive');
  })();

  /* ── MOBILE MENU ── */
  function toggleMenu() {
    const navMenu = document.getElementById('nav-menu');
    navMenu.classList.toggle('active');
  }

  /* ── SCROLL REVEAL ── */
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });

  const revealElements = document.querySelectorAll('.reveal');
  if(revealElements.length > 0) {
      revealElements.forEach(el => observer.observe(el));
  }
  
  /* ── READING PROGRESS BAR ── */
  window.addEventListener('scroll', () => {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrolled = (winScroll / height) * 100;
    const progressBar = document.getElementById('reading-progress');
    if (progressBar) progressBar.style.width = scrolled + '%';
  });
  
  /* ── CLEANUP LEFTOVER SPACES ── */
  document.addEventListener("DOMContentLoaded", function() {
    if (document.querySelector('.post-container')) {
      const postBodies = document.querySelectorAll('.post-body');
      postBodies.forEach(body => {
        let node = body.firstChild;
        while (node) {
          let next = node.nextSibling;
          if (node.nodeName === 'BR' || 
             (node.nodeType === 3 && node.textContent.trim() === '') ||
             (node.classList && node.classList.contains('separator')) ||
             (node.nodeName === 'P' && node.innerHTML.trim() === '')) {
            node.remove();
          } else {
            break;
          }
          node = next;
        }
      });
    }
  });
//
